def obtener_espejos(simbolo, umbral=85):
    if simbolo not in MATRIZ_4H:
        return f"No hay datos para {simbolo}", []

    correlaciones = MATRIZ_4H[simbolo]
    
    clones = {par: valor for par, valor in correlaciones.items() if valor >= umbral}
    opuestos = {par: valor for par, valor in correlaciones.items() if valor <= -umbral}
    
    return clones, opuestos